#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int value;
    struct Node* next;
} Node;

void deleteNode(Node** head, int value) {
    if (*head == NULL) return;
    if ((*head)->value == value) {
        Node* tmp = *head;
        *head = (*head)->next;
        free(tmp);
        return;
    }
    Node* cur = *head;
    while (cur->next != NULL) {
        if (cur->next->value == value) {
            Node* tmp = cur->next;
            cur->next = cur->next->next;
            free(tmp);
            return;
        }
        cur = cur->next;
    }
}

void printList(Node* head) {
    while (head != NULL) {
        printf("%d", head->value);
        head = head->next;
        if (head != NULL) printf(" ");
    }
    printf("\n");
}

int main() {
    int T; scanf("%d", &T);
    while (T--) {
        int n, x; scanf("%d %d", &n, &x);
        Node* head = NULL; Node* tail = NULL;
        for (int i = 0; i < n; ++i) {
            int v; scanf("%d", &v);
            Node* nd = (Node*)malloc(sizeof(Node));
            nd->value = v; nd->next = NULL;
            if (head == NULL) head = tail = nd; else { tail->next = nd; tail = nd; }
        }
        deleteNode(&head, x);
        printList(head);
        while (head) { Node* tmp = head; head = head->next; free(tmp); }
    }
    return 0;
}

