import java.io.*;
import java.util.*;

public class Main {
    static class Node {
        int value; Node next;
        Node(int v) { value = v; }
    }

    static Node deleteNode(Node head, int value) {
        if (head == null) return null;
        if (head.value == value) return head.next;
        Node cur = head;
        while (cur.next != null) {
            if (cur.next.value == value) {
                cur.next = cur.next.next;
                break;
            }
            cur = cur.next;
        }
        return head;
    }

    static String listToString(Node head) {
        StringBuilder sb = new StringBuilder();
        while (head != null) {
            sb.append(head.value);
            head = head.next;
            if (head != null) sb.append(' ');
        }
        return sb.toString();
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        for (int t = 0; t < T; ++t) {
            st = new StringTokenizer(br.readLine());
            int n = Integer.parseInt(st.nextToken());
            int x = Integer.parseInt(st.nextToken());
            st = new StringTokenizer(br.readLine());
            Node head = null, tail = null;
            for (int i = 0; i < n; ++i) {
                int v = Integer.parseInt(st.nextToken());
                Node nd = new Node(v);
                if (head == null) head = tail = nd; else { tail.next = nd; tail = nd; }
            }
            head = deleteNode(head, x);
            out.append(listToString(head)).append('\n');
        }
        System.out.print(out.toString());
    }
}

