import sys

def delete_node(head, value):
    if head is None:
        return None
    if head.value == value:
        return head.next
    cur = head
    while cur.next is not None:
        if cur.next.value == value:
            cur.next = cur.next.next
            break
        cur = cur.next
    return head

class Node:
    __slots__ = ('value', 'next')
    def __init__(self, v):
        self.value = v
        self.next = None

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        n = int(next(it)); x = int(next(it))
        head = None; tail = None
        for _ in range(n):
            v = int(next(it))
            nd = Node(v)
            if head is None:
                head = tail = nd
            else:
                tail.next = nd
                tail = nd
        head = delete_node(head, x)
        vals = []
        cur = head
        while cur is not None:
            vals.append(str(cur.value))
            cur = cur.next
        out_lines.append(' '.join(vals))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

